// src/lib.rs\n\n/// Represents a message in the pub-sub system.\npub struct Message {\n    pub topic: String,\n    pub payload: String,\n}  \n\n/// Implements a simple pub-sub system.\npub struct PubSub {\n    subscribers: std::collections::HashMap<String, Vec<Box<dyn Fn(&Message)>>>,\n}\n\nimpl PubSub {\n    pub fn new() -> Self {\n        PubSub {\n            subscribers: std::collections::HashMap::new(),\n        }\n    }\n\n    /// Subscribe to a topic with a callback function.\n    pub fn subscribe<F>(&mut self, topic: String, callback: F)\n    where\n        F: Fn(&Message) + 'static,\n    {\n        self.subscribers\n            .entry(topic)\n            .or_insert_with(Vec::new)\n            .push(Box::new(callback));\n    }\n\n    /// Publish a message to a topic.\n    pub fn publish(&self, topic: &str, payload: String) {\n        if let Some(callbacks) = self.subscribers.get(topic) {\n            let message = Message {\n                topic: topic.to_string(),\n                payload,\n            };\n            for callback in callbacks {\n                callback(&message);\n            }\n        }\n    }\n}